import { ComponentContext } from "@teambit/generator";


export function themeStyles(context: ComponentContext) {
  return {
    relativePath: `${context.name}.module.css`,
    content: `@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;700&display=swap');

.${context.nameCamelCase} {
  /* use a font family here to apply a default font
     on theme children. */
  font-family: var(--typography-font-family);

  /* use the theme background color to apply for all
     components in your tree. */
  background-color: var(--colors-surface-background);
  color: var(--colors-text-color);
}

:global(body) {
  margin: 0;
}
`
  }
}
